// Production service worker. Caches assets listed in service-worker-assets.js
// (generated by the Blazor PWA SDK) so the app is installable and works offline
// for shell navigations. API requests always go to the network.
self.importScripts('./service-worker-assets.js');
self.addEventListener('install', event => event.waitUntil(onInstall(event)));
self.addEventListener('activate', event => event.waitUntil(onActivate(event)));
self.addEventListener('fetch', event => event.respondWith(onFetch(event)));

const cacheNamePrefix = 'offline-cache-';
const cacheName = `${cacheNamePrefix}${self.assetsManifest.version}`;
const offlineAssetsInclude = [/\.dll$/, /\.pdb$/, /\.wasm/, /\.html/, /\.js$/, /\.json$/, /\.css$/, /\.woff$/, /\.png$/, /\.jpe?g$/, /\.gif$/, /\.ico$/, /\.blat$/, /\.dat$/, /\.svg$/, /\.webmanifest$/];
const offlineAssetsExclude = [/^service-worker\.js$/];

async function onInstall(event) {
    self.skipWaiting();

    const assetsRequests = self.assetsManifest.assets
        .filter(asset => offlineAssetsInclude.some(pattern => pattern.test(asset.url)))
        .filter(asset => !offlineAssetsExclude.some(pattern => pattern.test(asset.url)))
        .map(asset => new Request(asset.url, { integrity: asset.hash, cache: 'no-cache' }));
    await caches.open(cacheName).then(cache => cache.addAll(assetsRequests));
}

async function onActivate(event) {
    // Drop previous offline caches.
    const cacheKeys = await caches.keys();
    await Promise.all(cacheKeys
        .filter(key => key.startsWith(cacheNamePrefix) && key !== cacheName)
        .map(key => caches.delete(key)));
}

async function onFetch(request) {
    let cachedResponse = null;
    if (request.request.method === 'GET') {
        // For navigation requests, serve index.html from cache (SPA shell).
        const shouldServeIndexHtml = request.request.mode === 'navigate';
        const lookup = shouldServeIndexHtml ? 'index.html' : request.request;
        const cache = await caches.open(cacheName);
        cachedResponse = await cache.match(lookup);
    }
    return cachedResponse || fetch(request.request);
}

self.addEventListener('push', event => {
    if (!event.data) return;
    const data = event.data.json();
    event.waitUntil(
        self.registration.showNotification(data.title || 'Eatah', {
            body: data.body || '',
            icon: data.icon || '/icons/app-icon.svg',
            badge: data.badge || '/icons/app-icon.svg',
            data: data.data
        })
    );
});

self.addEventListener('notificationclick', event => {
    event.notification.close();
    event.waitUntil(clients.openWindow('/'));
});

